{
  "$schema": "https://metaharness.dev/schemas/mcp-policy.v1.json",
  "description": "@metaharness/example-gcp — read-only GCP tool policy. Mutations are NOT granted by default; pass --allow-mutations at harness invocation to opt in.",
  "defaultDeny": true,
  "allowNetwork": false,
  "allowShell": false,
  "allowFileWrite": false,
  "requireApprovalForDangerous": true,
  "toolTimeoutMs": 20000,
  "maxToolCallsPerTurn": 10,
  "auditLog": true,
  "auditLogPath": ".harness/audit/gcp-tool-calls.jsonl",
  "mutations_require_flag": "--allow-mutations",
  "grantedTools": [
    {
      "name": "gcp__list_projects",
      "description": "List GCP projects accessible to the authenticated principal.",
      "sdk": "@google-cloud/resource-manager v5 — ProjectsClient.listProjects()",
      "reads": ["project.name", "project.projectId", "project.state", "project.labels"],
      "mutates": false
    },
    {
      "name": "gcp__get_project",
      "description": "Fetch metadata for a single GCP project by resource name.",
      "sdk": "@google-cloud/resource-manager v5 — ProjectsClient.getProject({ name: 'projects/<id>' })",
      "reads": ["project.displayName", "project.createTime", "project.parent"],
      "mutates": false
    },
    {
      "name": "gcp__list_secrets",
      "description": "List secret names and metadata in a project. Does NOT read secret values.",
      "sdk": "@google-cloud/secret-manager v5 — SecretManagerServiceClient.listSecrets({ parent: 'projects/<id>' })",
      "reads": ["secret.name", "secret.createTime", "secret.replication", "secret.labels"],
      "mutates": false
    },
    {
      "name": "gcp__get_secret_metadata",
      "description": "Fetch metadata for a named secret. Does NOT read the secret value or any version payload.",
      "sdk": "@google-cloud/secret-manager v5 — SecretManagerServiceClient.getSecret({ name: 'projects/<id>/secrets/<name>' })",
      "reads": ["secret.name", "secret.replication", "secret.etag"],
      "mutates": false
    },
    {
      "name": "gcp__list_buckets",
      "description": "List Cloud Storage buckets in a project.",
      "sdk": "@google-cloud/storage v7 — new Storage({ projectId }).getBuckets()",
      "reads": ["bucket.name", "bucket.location", "bucket.storageClass"],
      "mutates": false
    },
    {
      "name": "gcp__get_bucket_metadata",
      "description": "Fetch metadata for a named bucket, including public-access-prevention and IAM config.",
      "sdk": "@google-cloud/storage v7 — bucket.getMetadata()",
      "reads": ["bucket.iamConfiguration", "bucket.publicAccessPrevention", "bucket.versioning"],
      "mutates": false
    },
    {
      "name": "gcp__get_object_metadata",
      "description": "Fetch metadata for a named storage object. Does NOT download the object content.",
      "sdk": "@google-cloud/storage v7 — bucket.file('<name>').getMetadata()",
      "reads": ["object.name", "object.size", "object.contentType", "object.md5Hash"],
      "mutates": false
    }
  ],
  "deniedTools": [
    {
      "name": "gcp__create_secret",
      "reason": "mutation — requires --allow-mutations"
    },
    {
      "name": "gcp__add_secret_version",
      "reason": "mutation — requires --allow-mutations"
    },
    {
      "name": "gcp__delete_secret",
      "reason": "mutation — requires --allow-mutations"
    },
    {
      "name": "gcp__create_bucket",
      "reason": "mutation — requires --allow-mutations"
    },
    {
      "name": "gcp__delete_bucket",
      "reason": "mutation — requires --allow-mutations"
    },
    {
      "name": "gcp__set_iam_policy",
      "reason": "mutation — requires --allow-mutations"
    },
    {
      "name": "gcp__get_secret_version",
      "reason": "returns secret plaintext — never granted; access secret values out-of-band via gcloud CLI with explicit human approval"
    }
  ]
}
